import{_ as r,C as n,o as t,c as s,a0 as e,b as l,w as i,a as d,E as c,a1 as p}from"./chunks/framework.B3sz4m_N.js";const u=""+new URL("../report/ai-pipeline-07-tooling-comparison.png",import.meta.url).href,_=JSON.parse('{"title":"Tooling Comparison (OSS vs SaaS)","description":"Bionic + team Cursor subscription, PHPStan, Rector — pilot choices; budget for Bionic/other; no AI in CI.","frontmatter":{"title":"Tooling Comparison (OSS vs SaaS)","description":"Bionic + team Cursor subscription, PHPStan, Rector — pilot choices; budget for Bionic/other; no AI in CI."},"headers":[],"relativePath":"reports/ai-augmented-dev-pipeline/07-tooling-comparison.md","filePath":"reports/ai-augmented-dev-pipeline/07-tooling-comparison.md"}'),h={name:"reports/ai-augmented-dev-pipeline/07-tooling-comparison.md"};function g(m,o,b,C,P,f){const a=n("Mermaid");return t(),s("div",null,[o[1]||(o[1]=e('<figure class="report-section-image-wrapper" aria-labelledby="fig-tooling-caption"><img src="'+u+'" alt="Two conduits feeding one container with a max level marked" loading="lazy" class="report-section-image"><figcaption id="fig-tooling-caption">Two conduits feeding one container with a max level marked</figcaption></figure><h1 id="tooling-comparison-oss-vs-saas" tabindex="-1">Tooling Comparison (OSS vs SaaS) <a class="header-anchor" href="#tooling-comparison-oss-vs-saas" aria-label="Permalink to &quot;Tooling Comparison (OSS vs SaaS)&quot;">​</a></h1><h2 id="_1-problem-context" tabindex="-1">1. Problem Context <a class="header-anchor" href="#_1-problem-context" aria-label="Permalink to &quot;1. Problem Context&quot;">​</a></h2><p>Pipeline needs proven tools only; no hallucinated or speculative tooling. Cursor is a team subscription with limits (fixed/cap per seat). Budget £200 (or £500) applies to Bionic and other AI tools; Bionic only for PR at pilot, no CodeRabbit or Copilot.</p><h2 id="_2-ai-opportunity" tabindex="-1">2. AI Opportunity <a class="header-anchor" href="#_2-ai-opportunity" aria-label="Permalink to &quot;2. AI Opportunity&quot;">​</a></h2><p>AI is used only in PR bot (Bionic) and local IDE (Cursor). CI is deterministic (PHPStan, Rector, PHPUnit/Pest). No AI in CI; no paid indexing. Opportunity is cost control and reversibility while still getting first-pass review and local suggestions.</p><h2 id="_3-proposed-architecture" tabindex="-1">3. Proposed Architecture <a class="header-anchor" href="#_3-proposed-architecture" aria-label="Permalink to &quot;3. Proposed Architecture&quot;">​</a></h2>',7)),(t(),l(p,null,{default:i(()=>[c(a,{id:"mermaid-19",class:"mermaid",graph:"flowchart%20TB%0A%20%20subgraph%20OSS%5BOSS%20%2F%20No%20AI%20cost%5D%0A%20%20%20%20PHPStan%5BPHPStan%5D%0A%20%20%20%20Rector%5BRector%5D%0A%20%20%20%20Pest%5BPHPUnit%2FPest%5D%0A%20%20%20%20Bionic%5BBionic%20PR%20bot%5D%0A%20%20end%0A%20%20subgraph%20SaaS_controlled%5BTeam%20Cursor%20subscription%5D%0A%20%20%20%20Cursor%5BCursor%5D%0A%20%20end%0A%20%20PR%5BPull%20Request%5D%20--%3E%20PHPStan%0A%20%20PR%20--%3E%20Rector%0A%20%20PR%20--%3E%20Pest%0A%20%20PR%20--%3E%20Bionic%0A%20%20Dev%5BDeveloper%5D%20--%3E%20Cursor%0A%20%20Cursor%20-.-%3E%7Csuggestions%20only%7C%20Dev%0A"})]),fallback:i(()=>[...o[0]||(o[0]=[d(" Loading... ",-1)])]),_:1})),o[2]||(o[2]=e('<h2 id="_4-tooling-options-oss-vs-saas" tabindex="-1">4. Tooling Options (OSS vs SaaS) <a class="header-anchor" href="#_4-tooling-options-oss-vs-saas" aria-label="Permalink to &quot;4. Tooling Options (OSS vs SaaS)&quot;">​</a></h2><p><strong>Comparison table (OSS vs SaaS)</strong></p><table tabindex="0"><thead><tr><th>Area</th><th>OSS / self-hosted</th><th>SaaS</th><th>Pilot choice</th></tr></thead><tbody><tr><td>PR review</td><td>Bionic (GitHub App), Reviewpad</td><td>CodeRabbit, GitHub Copilot for PRs</td><td><strong>Bionic only</strong> (budget £200); £500 allows CodeRabbit</td></tr><tr><td>Static analysis</td><td>PHPStan, Psalm, Rector, PHPCompatibility</td><td>—</td><td><strong>PHPStan, Rector</strong> in CI</td></tr><tr><td>Refactor / migration</td><td>Rector (CI), PHPStan</td><td>Cursor, Copilot (local)</td><td><strong>Rector in CI; team Cursor local</strong></td></tr><tr><td>Test generation</td><td>PHPUnit, Pest, scaffolding</td><td>Cursor, Copilot</td><td><strong>Team Cursor only</strong> (ad-hoc, within plan limits)</td></tr><tr><td>Documentation</td><td>MkDocs, Docusaurus, phpDocumentor</td><td>Cursor, Copilot, Sweep</td><td><strong>Team Cursor only</strong> (ad-hoc, within plan limits)</td></tr><tr><td>IDE / local</td><td>—</td><td>Cursor, GitHub Copilot</td><td><strong>Team Cursor subscription only</strong></td></tr></tbody></table><p><strong>Cursor:</strong> Team-based subscription with limits. Cost is fixed or cap per seat; £200/£500 budget applies to Bionic (and CodeRabbit at £500), not Cursor. Rate limits follow the subscription plan (e.g. fast/slow request caps per month); align internal guidance (e.g. “prefer small selection”, “no full-file paste”) to stay within plan. No overage spend for Cursor when within plan; hitting plan limits is a usage/availability issue, not a cost breach. Reversibility: reduce seats or change plan rather than only restrict by repo.</p><h2 id="_5-guardrails-controls" tabindex="-1">5. Guardrails &amp; Controls <a class="header-anchor" href="#_5-guardrails-controls" aria-label="Permalink to &quot;5. Guardrails &amp; Controls&quot;">​</a></h2><ul><li><strong>CI:</strong> No SaaS AI in GitHub Actions. Grep on PR for <code>openai</code>, <code>anthropic</code>, etc. in workflows (Cost Governor).</li><li><strong>PR bot:</strong> Bionic: 15 PRs/repo/week; 30k tokens/PR max. No CodeRabbit at pilot budget.</li><li><strong>Cursor:</strong> Team subscription only; stay within plan limits (e.g. fast/slow caps); default model, no paid index. Document plan caps; align internal guidance.</li></ul><h2 id="_6-failure-modes" tabindex="-1">6. Failure Modes <a class="header-anchor" href="#_6-failure-modes" aria-label="Permalink to &quot;6. Failure Modes&quot;">​</a></h2><ul><li><strong>Vendor deprecated or pricing change:</strong> Bionic OSS or free tier; fallback human-only review. Cursor: policy to restrict by repo if needed.</li><li><strong>Tool substitution:</strong> If Bionic unavailable, human-only review until replacement (no new tool without Architect/Cost Governor alignment).</li></ul><h2 id="_7-kpis" tabindex="-1">7. KPIs <a class="header-anchor" href="#_7-kpis" aria-label="Permalink to &quot;7. KPIs&quot;">​</a></h2><ul><li><strong>Cost:</strong> Bionic and other AI tools: monthly spend ≤ £200 (or £500 if agreed); weekly check; alert at £180 (or £450). Cursor: team subscription, no separate spend tracking when within plan.</li><li><strong>CI health:</strong> No AI in CI; workflow success and job duration as per DevOps checklist.</li></ul><h2 id="_8-actionable-next-steps" tabindex="-1">8. Actionable Next Steps <a class="header-anchor" href="#_8-actionable-next-steps" aria-label="Permalink to &quot;8. Actionable Next Steps&quot;">​</a></h2><ol><li>Confirm budget ceiling for Bionic/other (£200 or £500) and lock tool set; confirm team Cursor subscription and document plan limits.</li><li>Document chosen stack in repo (README or docs) and in one-pager.</li><li>Enforce &quot;no AI in CI&quot; via code review of every workflow change.</li></ol>',12))])}const A=r(h,[["render",g]]);export{_ as __pageData,A as default};
